def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    part = np.exp(-b/(a+1)) * ((ratio - a) ** 4) / (a * b + 1)
                    priority += part * np.sin(ratio * b / (a + 2) * 1.5)
            priority += np.tanh(np.sqrt(ratio - 8) * 3) * 20
            if i % 2 == 0:
                for c in range(5):
                    priority += np.cos(c * ratio * 0.5) * (c + 1)
        elif 5 < ratio <= 8:
            for p in range(1, 10):
                inner_sum = 0
                for q in range(1, p + 4):
                    val = (ratio - p) ** 2.5 / (q + 1) * np.tanh(ratio * q / (p + 2))
                    inner_sum += val
                priority += np.sin(inner_sum * ratio) * (p * 1.1)
            priority -= np.log1p(ratio) * 15
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 7
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 20):
                s += ((ratio - 2) ** r) * np.cos(r * ratio / 1.3) / (r ** 2 + 1)
            priority = s * np.sin(5 * ratio) + np.tanh(2 * (5 - ratio)) * 8
            if bin_cap > item * 1.5:
                priority -= np.log(bin_cap - item + 1) * 5
            else:
                for k in range(3):
                    priority += np.sin((i + k) * ratio * 0.8) * (k + 1) * 0.7
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n * n + 0.3) * np.cos(n * ratio * 3)
            penalty = np.exp(-(ratio - 1) * 10)
            if bin_cap < item * 1.2:
                penalty += np.sqrt(item * bin_cap) * 3.5
            else:
                penalty -= np.cos(15 * ratio) * 2
            priority = s + penalty
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m+0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 20):
                s += ((1 - ratio) ** t) / (t * 3.5) * np.sin(t * item * 1.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for u in range(1, 8):
                priority += ((1 - ratio) ** u) * np.cos(u * item * 1.3) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 18):
                val = ((0.5 - ratio) ** w) / (w * 2) * np.cos(w * ratio * 2.5)
                s += val
            priority = s + 2 / (bin_cap + 2)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for x in range(1, 10):
                priority += ((0.5 - ratio) ** x) / (x * 4) * np.sin(item * x * 0.85)
        else:
            s = 0
            for y in range(1, 15):
                s += ((0.2 - ratio) ** y) / (y * 6) * np.cos(y * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for z in range(1, 12):
                priority += ((0.2 - ratio) ** z) / (z * 5) * np.sin(item * z * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.4) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
